code = """import json

# Load the EMA results
result_path = locals()['var_functions.execute_python:60']
with open(result_path, 'r') as f:
    ema_data = json.load(f)

cpc_ema_results = ema_data['cpc_ema_results']

# Get the top CPC codes by EMA
top_cpc_codes = sorted(cpc_ema_results.items(), key=lambda x: x[1]['best_ema'], reverse=True)[:20]

print("Top 20 CPC level 4 codes by EMA:")
print("="*60)
for i, (code, data) in enumerate(top_cpc_codes, 1):
    print(f"{i:2d}. {code}: EMA={data['best_ema']:.4f} (best year: {data['best_year']})")

# Now let's find full CPC codes at level 4 in the definition database
cpc_level4_codes = [item[0] for item in top_cpc_codes]

# Check a few to see their format
print("\nSample CPC codes to look up:")
for code in cpc_level4_codes[:10]:
    print(f"  {code}")

# We need to find these codes in the cpc_definition table
# The issue is that CPC codes in our data are like "C04B35" (level 4)
# but the cpc_definition has codes like "C04B35/04" (level 10+)

# Let's save the top codes for querying
top_50_codes = [item[0] for item in sorted(cpc_ema_results.items(), key=lambda x: x[1]['best_ema'], reverse=True)[:50]]

print(f"\nGenerated list of {len(top_50_codes)} top CPC codes for title lookup")

result = {
    'top_50_cpc_codes': top_50_codes,
    'total_analyzed': len(cpc_ema_results)
}

print('__RESULT__:')
print(json.dumps(result))"""

